// Load cursor from incoming static data
const staticData = $getWorkflowStaticData('global');
const processedIds = new Set(staticData.amazon_report_ids || []);

const reports = ($input.first().json.reports || []).filter(r => r.processingStatus === 'DONE');

// Filter to big 60-day window reports + most recent daily
const bigReports = reports.filter(r => {
  const start = new Date(r.dataStartTime);
  const end = new Date(r.dataEndTime);
  return (end - start) > 30 * 86400000;
});
const latestDaily = reports.find(r => {
  const start = new Date(r.dataStartTime);
  const end = new Date(r.dataEndTime);
  return (end - start) <= 35 * 86400000;
});

const toProcess = [...bigReports];
if (latestDaily && !bigReports.find(r => r.reportId === latestDaily.reportId)) {
  toProcess.unshift(latestDaily);
}

// Incremental: skip already-processed
const filtered = toProcess.filter(r => !processedIds.has(r.reportId));

if (filtered.length === 0) {
  return [{ json: { _no_reports: true, message: 'No new Amazon reports' } }];
}

return filtered.map(r => ({ json: r }));

const tsv = $input.first().json.data;
const reportId = $('Get Report Details').first().json.reportId;
const lines = tsv.split('\n').filter(l => l.trim());
const headers = lines[0].split('\t');
const rows = lines.slice(1).map(l => {
  const vals = l.split('\t');
  const row = {};
  headers.forEach((h, i) => row[h] = vals[i]?.trim() || '');
  return row;
});

// Reason mapping
function mapAmazonReason(reason) {
  const map = {
    'CR-DEFECTIVE': 'defective', 'CR-QUALITY_UNACCEPTABLE': 'defective',
    'CR-DAMAGED_BY_CARRIER': 'damaged_in_transit', 'CR-DAMAGED_BY_FC': 'damaged_in_transit',
    'CR-WRONG_ITEM': 'wrong_item', 'CR-NOT_AS_DESCRIBED': 'not_as_described',
    'CR-MISSED_ESTIMATED_DELIVERY': 'arrived_late', 'CR-SWITCHEROO': 'wrong_item',
    'CR-MISSING_PARTS': 'missing_parts', 'CR-BUYER_REMORSE': 'no_longer_needed',
    'CR-UNWANTED_ITEM': 'no_longer_needed', 'CR-NO_REASON': 'other',
    'LOST_IN_TRANSIT': 'damaged_in_transit'
  };
  return map[reason] || 'other';
}

function mapAmazonStatus(status) {
  const map = {
    'Approved': 'approved', 'Completed': 'refunded',
    'Unit returned': 'received', 'Pending': 'requested', 'Denied': 'rejected'
  };
  return map[status] || 'requested';
}

function parseDate(d) {
  if (!d || !d.trim()) return null;
  const parsed = new Date(d);
  return isNaN(parsed) ? null : parsed.toISOString();
}

const seenRMAs = new Set();
const results = [];

for (const row of rows) {
  const rma = row['Amazon RMA ID'];
  if (!rma || seenRMAs.has(rma)) continue;
  seenRMAs.add(rma);

  let status = mapAmazonStatus(row['Return request status']);
  if (row['Resolution'] === 'StandardRefund' || row['Resolution'] === 'RefundAtFirstScan') {
    status = 'refunded';
  }

  results.push({
    json: {
      _reportId: reportId,
      _type: 'amazon',
      order_number: row['Order ID'],
      sku: row['Merchant SKU'],
      return_data: {
        status,
        reason: mapAmazonReason(row['Return Reason']),
        reason_detail: row['Return Reason'],
        rma_number: rma,
        return_label_tracking: row['Tracking ID'] || null,
        return_carrier: row['Return carrier'] || null,
        requested_at: parseDate(row['Return request date']),
        received_at: parseDate(row['Return delivery date']),
        return_shipping_cost: parseFloat(row['Label cost']) || 0,
        paid_by: row['Label to be paid by'] === 'Amazon' ? 'channel' : 'seller',
        external_ids: { amazon_rma: rma, amazon_order_item: row['Order Item ID'] },
        metadata: {
          label_type: row['Label type'],
          return_type: row['Return type'],
          resolution: row['Resolution'],
          is_prime: row['Is prime'] === 'Y',
          asin: row['ASIN'],
          in_policy: row['In policy'] === 'Y',
          safet_claim_id: row['SafeT claim id'] || null
        }
      },
      quantity: parseInt(row['Return quantity']) || 1,
      refund_amount: parseFloat(row['Refunded Amount']) || parseFloat(row['Order Amount']) || 0,
      resolution: row['Resolution']
    }
  });
}

if (results.length === 0) {
  return [{ json: { _no_items: true, _reportId: reportId } }];
}
return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const orderRows = item.json;
  // Supabase returns array; httpRequest node unwraps, so check
  const orderId = Array.isArray(orderRows) ? orderRows[0]?.id : orderRows?.id;

  // Get the paired input from the previous node by index
  const idx = items.indexOf(item);
  const original = $('Has Items?').all()[idx]?.json;

  if (!orderId || !original) continue;

  const rd = original.return_data;
  rd.order_id = orderId;

  results.push({
    json: {
      ...original,
      order_id: orderId,
      return_data: rd
    }
  });
}

if (results.length === 0) {
  return [{ json: { _empty: true } }];
}
return results;

const items = $input.all();
const originals = $('Match Orders').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const upserted = Array.isArray(items[i].json) ? items[i].json[0] : items[i].json;
  const orig = originals[i]?.json;
  if (!upserted?.id || !orig) continue;

  // Build return_item record
  if (orig.sku && orig.order_id) {
    results.push({
      json: {
        _action: 'return_item_lookup',
        return_id: upserted.id,
        order_id: orig.order_id,
        sku: orig.sku,
        quantity: orig.quantity || 1,
        reason: orig.return_data.reason,
        refund_amount: orig.refund_amount || 0,
        resolution: orig.resolution,
        rma_number: orig.return_data.rma_number,
        _type: orig._type
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { _empty: true } }];
}
return results;

const items = $input.all();
const originals = $('Prepare Return Items').all();
const returnItems = [];
const refunds = [];

for (let i = 0; i < items.length; i++) {
  const oiRows = Array.isArray(items[i].json) ? items[i].json : [items[i].json];
  const oi = oiRows[0];
  const orig = originals[i]?.json;
  if (!orig) continue;

  if (oi?.id) {
    returnItems.push({
      return_id: orig.return_id,
      order_item_id: oi.id,
      variant_id: oi.variant_id || null,
      quantity: orig.quantity,
      reason: orig.reason
    });
  }

  if (orig.refund_amount > 0) {
    refunds.push({
      order_id: orig.order_id,
      return_id: orig.return_id,
      refund_type: orig.resolution === 'StandardRefund' ? 'full' : 'partial',
      amount: orig.refund_amount,
      total_refund: orig.refund_amount,
      status: 'completed',
      channel_id: '7f84462f-86c8-4e09-abb6-285631db0d83',
      external_ref: 'amz-' + orig.rma_number,
      metadata: { resolution: orig.resolution }
    });
  }
}

const output = [];
if (returnItems.length > 0) output.push({ json: { _batch: 'return_items', items: returnItems } });
if (refunds.length > 0) output.push({ json: { _batch: 'refunds', items: refunds } });
if (output.length === 0) return [{ json: { _empty: true } }];
return output;

// Save processed report IDs to static data
const staticData = $getWorkflowStaticData('global');
const processedIds = new Set(staticData.amazon_report_ids || []);

// Collect all reportIds from the batch
const allItems = $('Parse Amazon TSV').all();
for (const item of allItems) {
  if (item.json._reportId) processedIds.add(item.json._reportId);
}

staticData.amazon_report_ids = [...processedIds];

return [{ json: { status: 'amazon_cursor_saved', count: processedIds.size } }];

const data = $input.first().json;
const returns = data?.returnOrders || [];

function mapWalmartReason(reason) {
  const map = {
    'DAMAGED': 'damaged_in_transit', 'DEFECTIVE': 'defective',
    'WRONG_ITEM': 'wrong_item', 'NOT_AS_DESCRIBED': 'not_as_described',
    'LOST_IN_TRANSIT': 'damaged_in_transit', 'ARRIVED_LATE': 'arrived_late',
    'MISSING_PARTS': 'missing_parts', 'NO_LONGER_NEEDED': 'no_longer_needed',
    'CHANGED_MIND': 'no_longer_needed'
  };
  return map[reason] || 'other';
}

const results = [];
for (const ret of returns) {
  const firstLine = ret.returnOrderLines?.[0];
  const reason = firstLine?.returnReason || 'other';
  const rma = 'WM-' + ret.returnOrderId;
  const totalRefund = ret.totalRefundAmount?.currencyAmount || 0;

  results.push({
    json: {
      _type: 'walmart',
      order_number: ret.customerOrderId,
      return_data: {
        status: totalRefund > 0 ? 'refunded' : 'approved',
        reason: mapWalmartReason(reason),
        reason_detail: firstLine?.returnDescription || reason,
        rma_number: rma,
        requested_at: ret.returnOrderDate,
        return_shipping_cost: 0,
        paid_by: 'channel',
        external_ids: { walmart_return_id: ret.returnOrderId },
        metadata: {
          refund_mode: ret.refundMode,
          return_by_date: ret.returnByDate,
          customer_email: ret.customerEmailId
        }
      },
      return_lines: (ret.returnOrderLines || []).map(line => ({
        sku: line.item?.sku,
        reason: mapWalmartReason(line.returnReason)
      })),
      refund_amount: totalRefund,
      walmart_return_id: ret.returnOrderId
    }
  });
}

if (results.length === 0) {
  return [{ json: { _empty: true, message: 'No Walmart returns' } }];
}
return results;

const items = $input.all();
const originals = $('Has WM Returns?').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const orderRows = Array.isArray(items[i].json) ? items[i].json : [items[i].json];
  const orderId = orderRows[0]?.id;
  const orig = originals[i]?.json;
  if (!orderId || !orig) continue;

  const rd = { ...orig.return_data, order_id: orderId };
  results.push({ json: { ...orig, order_id: orderId, return_data: rd } });
}

if (results.length === 0) return [{ json: { _empty: true } }];
return results;

const items = $input.all();
const originals = $('Match WM Orders').all();
const returnItems = [];
const refunds = [];

for (let i = 0; i < items.length; i++) {
  const upserted = Array.isArray(items[i].json) ? items[i].json[0] : items[i].json;
  const orig = originals[i]?.json;
  if (!upserted?.id || !orig) continue;

  // Each return line becomes a return_item lookup
  for (const line of (orig.return_lines || [])) {
    if (line.sku) {
      returnItems.push({
        _lookup: true,
        return_id: upserted.id,
        order_id: orig.order_id,
        sku: line.sku,
        quantity: 1,
        reason: line.reason
      });
    }
  }

  if (orig.refund_amount > 0) {
    refunds.push({
      order_id: orig.order_id,
      return_id: upserted.id,
      refund_type: 'full',
      amount: orig.refund_amount,
      total_refund: orig.refund_amount,
      status: 'completed',
      channel_id: '2da7e1e0-579e-4968-bdef-fa18492a6a86',
      external_ref: 'wm-' + orig.walmart_return_id,
      metadata: { refund_mode: orig.return_data.metadata?.refund_mode }
    });
  }
}

const output = [];
if (returnItems.length > 0) output.push({ json: { _batch: 'wm_return_items', items: returnItems } });
if (refunds.length > 0) output.push({ json: { _batch: 'wm_refunds', items: refunds } });
if (output.length === 0) return [{ json: { _empty: true } }];
return output;

// Update sync_cursors for walmart
const now = new Date().toISOString();
return [{ json: { sync_name: 'returns-sync-walmart', cursor_value: now, updated_at: now } }];
